import torch
from torchvision import models, transforms
from PIL import Image

class Model:
    def __init__(self):
        self.model = models.resnet50(pretrained=True)

        # Add custom final layer to adapt for single-output problem.
        num_ftrs = self.model.fc.in_features
        
        self.model.fc = torch.nn.Linear(num_ftrs, 3)

    def predict(self, img):
        # Convert input PIL Image object into Tensor for prediction using model.
        image_tensor = transforms.ToTensor()(img).unsqueeze_(0)

        return self.model(image_tensor)[0].argmax().item()